These functions implement the core functionality of Libdogecoin for address generation and validation, and are described in depth below. You can access them through a C program, by including the libdogecoin.h header in the source code and including the libdogecoin.a library at compile time. When using functions from either the Essential or Advanced Address API, include the -lunistring flag during the linking process. This is because the Advanced Address API uses the GNU libunistring library for Unicode string manipulation. To include the -lunistring flag during linking, simply add it to the linker command when building your project: gcc -o example example.c -ldogecoin -lunistring Ensure that the libunistring library is installed on your system before linking. generatePrivPubKeypair: int generatePrivPubKeypair(char* wif_privkey, char* p2pkh_pubkey, bool is_testnet) This function will populate provided string variables (privkey, pubkey) with freshly generated respective private and public keys, specifically for either mainnet or testnet as specified through the network flag (is_testnet). The function returns 1 on success and 0 on failure. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int privkeyLen = PRIVKEYWIFLEN; int pubkeyLen = P2PKHLEN; char privKey[privkeyLen]; char pubKey[pubkeyLen]; dogecoin_ecc_start(); generatePrivPubKeypair(privKey, pubKey, false); // generating a mainnet pair dogecoin_ecc_stop(); printf("My private key for mainnet is: %s\n", privKey); printf("My public key for mainnet is: %s\n", pubKey);
} generateHDMasterPubKeypair: int generateHDMasterPubKeypair(char* hd_privkey_master, char* p2pkh_pubkey_master, bool is_testnet) This function will populate provided string variables (privkey, pubkey) with freshly generated respective private and public keys for a hierarchical deterministic wallet, specifically for either mainnet or testnet as specified through the network flag (is_testnet). The function returns 1 on success and 0 on failure. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int masterPrivkeyLen = HDKEYLEN; // enough cushion int pubkeyLen = P2PKHLEN; char masterPrivKey[masterPrivkeyLen]; char masterPubKey[pubkeyLen]; dogecoin_ecc_start(); generateHDMasterPubKeypair(masterPrivKey, masterPubKey, false); dogecoin_ecc_stop(); printf("My private key for mainnet is: %s\n", masterPrivKey); printf("My public key for mainnet is: %s\n", masterPubKey);
} generateDerivedHDPubKey: int generateDerivedHDPubkey(const char* hd_privkey_master, char* p2pkh_pubkey) This function takes a given HD master private key (hd_privkey_master) and loads it into the provided pointer for the resulting derived public key (p2pkh_pubkey). This private key input should come from the result of generateHDMasterPubKeypair(). The function returns 1 on success and 0 on failure. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int masterPrivkeyLen = HDKEYLEN; // enough cushion int pubkeyLen = P2PKHLEN; char masterPrivKey[masterPrivkeyLen]; char masterPubKey[pubkeyLen]; char childPubKey[pubkeyLen]; dogecoin_ecc_start(); generateHDMasterPubKeypair(masterPrivKey, masterPubKey, false); generateDerivedHDPubkey(masterPrivKey, childPubKey); dogecoin_ecc_stop(); printf("master private key: %s\n", masterPrivKey); printf("master public key: %s\n", masterPubKey); printf("derived child key: %s\n", childPubKey);
} verifyPrivPubKeypair int verifyPrivPubKeypair(char* wif_privkey, char* p2pkh_pubkey, bool is_testnet) This function requires a previously generated key pair (wif_privkey, p2pkh_pubkey) and the network they were generated for (is_testnet). It then validates that the given public key was indeed derived from the given private key, returning 1 if the keys are associated and 0 if they are not. This could be useful prior to signing, or in some kind of wallet recovery tool to match keys. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int privkeyLen = PRIVKEYWIFLEN; int pubkeyLen = P2PKHLEN; char privKey[privkeyLen]; char pubKey[pubkeyLen]; dogecoin_ecc_start(); generatePrivPubKeypair(privKey, pubKey, false); if (verifyPrivPubKeypair(privKey, pubKey, false)) { printf("Keypair is valid.\n"); } else { printf("Keypair is invalid.\n"); } dogecoin_ecc_stop();
} verifyHDMasterPubKeypair int verifyHDMasterPubKeypair(char* hd_privkey_master, char* p2pkh_pubkey_master, bool is_testnet) This function validates that a given master private key matches a given master public key. This could be useful prior to signing, or in some kind of wallet recovery tool to match keys. This function requires a previously generated HD master key pair (hd_privkey_master, p2pkh_pubkey_master) and the network they were generated for (is_testnet). It then validates that the given public key was indeed derived from the given master private key, returning 1 if the keys are associated and 0 if they are not. This could be useful prior to signing, or in some kind of wallet recovery tool to match keys. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int masterPrivkeyLen = HDKEYLEN; // enough cushion int pubkeyLen = P2PKHLEN; char masterPrivKey[masterPrivkeyLen]; char masterPubKey[pubkeyLen]; dogecoin_ecc_start(); generateHDMasterPubKeypair(masterPrivKey, masterPubKey, false); if (verifyHDMasterPubKeypair(masterPrivKey, masterPubKey, false)) { printf("Keypair is valid.\n"); } else { printf("Keypair is invalid.\n"); } dogecoin_ecc_stop();
} verifyP2pkhAddress int verifyP2pkhAddress(char* p2pkh_pubkey, uint8_t len) This function accepts an existing public key (p2pkh_pubkey) and its length in characters (len) to perform some basic validation to determine if it looks like a valid Dogecoin address. It returns 1 if the address is valid and 0 if it is not. This is useful for wallets that want to check that a recipient address looks legitimate. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int privkeyLen = HDKEYLEN; // enough cushion int pubkeyLen = P2PKHLEN; char privKey[privkeyLen]; char pubKey[pubkeyLen]; dogecoin_ecc_start(); generatePrivPubKeypair(privKey, pubKey, false); if (verifyP2pkhAddress(pubKey, strlen(pubKey))) { printf("Address is valid.\n"); } else { printf("Address is invalid.\n"); } dogecoin_ecc_stop();
} getHDNodePrivateKeyWIFByPath char* getHDNodePrivateKeyWIFByPath(const char* masterkey, const char* derived_path, char* outaddress, bool outprivkey) This function derives a hierarchical deterministic child key by way of providing the extended master key, derived_path, outaddress and outprivkey. It will return the dogecoin_hdnode's private key serialized in WIF format if successful and exits if the proper arguments are not provided. C usage: #include "libdogecoin.h"
#include <assert.h>
#include <stdio.h> int main() { size_t extoutsize = 112; char* extout = dogecoin_char_vla(extoutsize); char* masterkey_main_ext = "dgpv51eADS3spNJh8h13wso3DdDAw3EJRqWvftZyjTNCFEG7gqV6zsZmucmJR6xZfvgfmzUthVC6LNicBeNNDQdLiqjQJjPeZnxG8uW3Q3gCA3e"; dogecoin_ecc_start(); u_assert_str_eq(getHDNodePrivateKeyWIFByPath(masterkey_main_ext, "m/44'/3'/0'/0/0", extout, true), "QNvtKnf9Qi7jCRiPNsHhvibNo6P5rSHR1zsg3MvaZVomB2J3VnAG"); u_assert_str_eq(extout, "dgpv5BeiZXttUioRMzXUhD3s2uE9F23EhAwFu9meZeY9G99YS6hJCsQ9u6PRsAG3qfVwB1T7aQTVGLsmpxMiczV1dRDgzpbUxR7utpTRmN41iV7"); dogecoin_ecc_stop(); free(extout);
} getHDNodeAndExtKeyByPath dogecoin_hdnode* getHDNodeAndExtKeyByPath(const char* masterkey, const char* derived_path, char* outaddress, bool outprivkey) This function derives a hierarchical deterministic child key by way of providing the extended master key, derived_path, outaddress and outprivkey. The masterkey can be either a private or public key, but if it is a public key, the outprivkey flag must be set to false and the derived_path must be a public derivation path. It will return the dogecoin_hdnode if successful and exits if the proper arguments are not provided. C usage: #include "libdogecoin.h"
#include <assert.h>
#include <stdio.h> int main() { size_t extoutsize = 112; char* extout = dogecoin_char_vla(extoutsize); char* masterkey_main_ext = "dgpv51eADS3spNJh8h13wso3DdDAw3EJRqWvftZyjTNCFEG7gqV6zsZmucmJR6xZfvgfmzUthVC6LNicBeNNDQdLiqjQJjPeZnxG8uW3Q3gCA3e"; dogecoin_ecc_start(); dogecoin_hdnode* hdnode = getHDNodeAndExtKeyByPath(masterkey_main_ext, "m/44'/3'/0'/0/0", extout, true); u_assert_str_eq(utils_uint8_to_hex(hdnode->private_key, sizeof hdnode->private_key), "09648faa2fa89d84c7eb3c622e06ed2c1c67df223bc85ee206b30178deea7927"); dogecoin_privkey_encode_wif((const dogecoin_key*)hdnode->private_key, &dogecoin_chainparams_main, privkeywif_main, &wiflen); u_assert_str_eq(privkeywif_main, "QNvtKnf9Qi7jCRiPNsHhvibNo6P5rSHR1zsg3MvaZVomB2J3VnAG"); u_assert_str_eq(extout, "dgpv5BeiZXttUioRMzXUhD3s2uE9F23EhAwFu9meZeY9G99YS6hJCsQ9u6PRsAG3qfVwB1T7aQTVGLsmpxMiczV1dRDgzpbUxR7utpTRmN41iV7"); dogecoin_ecc_stop(); dogecoin_hdnode_free(hdnode); free(extout);
} #include "libdogecoin.h"
#include <assert.h>
#include <stdio.h> int main() { char masterkey[HDKEYLEN] = {0}; char master_public_key[HDKEYLEN] = {0}; char extkeypath[KEYPATHMAXLEN] = "m/0/0/0/0/0"; char extpubkey[HDKEYLEN] = {0}; dogecoin_ecc_start(); // Generate a master key pair from the seed, and then get the master public key getHDRootKeyFromSeed(utils_hex_to_uint8("5eb00bbddcf069084889a8ab9155568165f5c453ccb85e70811aaed6f6da5fc19a5ac40b389cd370d086206dec8aa6c43daea6690f20ad3d8d48b2d2ce9e38e4"), MAX_SEED_SIZE, false, masterkey); getHDPubKey(masterkey, false, master_public_key); // Derive an extended normal (non-hardened) public key from the master public key getHDNodeAndExtKeyByPath(master_public_key, extkeypath, extpubkey, false); dogecoin_ecc_stop(); printf("%s\n", extpubkey);
} getDerivedHDAddress int getDerivedHDAddress(const char* masterkey, uint32_t account, bool ischange, uint32_t addressindex, char* outaddress, bool outprivkey) This function derives a hierarchical deterministic address by way of providing the extended master key, account, ischange and addressindex. It will return 1 if the function is successful and 0 if not. C usage: #include "libdogecoin.h"
#include <assert.h>
#include <stdio.h> int main() { size_t extoutsize = 112; char* extout = dogecoin_char_vla(extoutsize); char* masterkey_main_ext = "dgpv51eADS3spNJh8h13wso3DdDAw3EJRqWvftZyjTNCFEG7gqV6zsZmucmJR6xZfvgfmzUthVC6LNicBeNNDQdLiqjQJjPeZnxG8uW3Q3gCA3e"; dogecoin_ecc_start(); int res = getDerivedHDAddress(masterkey_main_ext, 0, false, 0, extout, true); u_assert_int_eq(res, true); u_assert_str_eq(extout, "dgpv5BeiZXttUioRMzXUhD3s2uE9F23EhAwFu9meZeY9G99YS6hJCsQ9u6PRsAG3qfVwB1T7aQTVGLsmpxMiczV1dRDgzpbUxR7utpTRmN41iV7"); dogecoin_ecc_stop(); free(extout);
} getDerivedHDAddressByPath int getDerivedHDAddressByPath(const char* masterkey, const char* derived_path, char* outaddress, bool outprivkey) This function derives an extended HD address by custom path in string format (derived_path). It returns 1 if the address is valid and 0 if it is not. C usage: #include "libdogecoin.h"
#include <assert.h>
#include <stdio.h> int main() { size_t extoutsize = 112; char* extout = dogecoin_char_vla(extoutsize); char* masterkey_main_ext = "dgpv51eADS3spNJh8h13wso3DdDAw3EJRqWvftZyjTNCFEG7gqV6zsZmucmJR6xZfvgfmzUthVC6LNicBeNNDQdLiqjQJjPeZnxG8uW3Q3gCA3e"; dogecoin_ecc_start(); res = getDerivedHDAddressByPath(masterkey_main_ext, "m/44'/3'/0'/0/0", extout, true); u_assert_int_eq(res, true); u_assert_str_eq(extout, "dgpv5BeiZXttUioRMzXUhD3s2uE9F23EhAwFu9meZeY9G99YS6hJCsQ9u6PRsAG3qfVwB1T7aQTVGLsmpxMiczV1dRDgzpbUxR7utpTRmN41iV7"); dogecoin_ecc_stop(); free(extout);
}

