These functions implement advanced functionality of Libdogecoin for address generation and validation, and are described in depth below. You can access them through a C program, by including the libdogecoin.h header in the source code and including the libdogecoin.a library at compile time. generateRandomEnglishMnemonic int generateRandomEnglishMnemonic(const ENTROPY_SIZE size, MNEMONIC mnemonic); This function generates a random English mnemonic phrase (seed phrase). The function returns 0 on success and -1 on failure. C usage: #include "libdogecoin.h"
#include <stdio.h> int main () { MNEMONIC seed_phrase; dogecoin_ecc_start(); generateRandomEnglishMnemonic("256", seed_phrase); dogecoin_ecc_stop(); printf("%s\n", seed_phrase);
} C++ usage: extern "C" {
#include "libdogecoin.h"
}
#include <iostream>
using namespace std; int main () { MNEMONIC seed_phrase; dogecoin_ecc_start(); generateRandomEnglishMnemonic("256", seed_phrase); dogecoin_ecc_stop(); cout << seed_phrase << endl;
} generateRandomEnglishMnemonicTPM dogecoin_bool generateRandomEnglishMnemonicTPM(MNEMONIC mnemonic, const int file_num, const dogecoin_bool overwrite); This function generates a random English mnemonic using a TPM (Trusted Platform Module). It stores the generated mnemonic in the provided mnemonic buffer. The file_num parameter specifies the encrypted storage file number, and the overwrite parameter indicates whether to overwrite an existing mnemonic in the encrypted storage. The function returns TRUE on success and FALSE on failure. C usage: #include "libdogecoin.h" int main() { MNEMONIC mnemonic; int file_num = 0; // Specify the TPM storage file number dogecoin_bool overwrite = TRUE; // Set to TRUE to overwrite existing mnemonic if (generateRandomEnglishMnemonicTPM(mnemonic, file_num, overwrite)) { printf("Generated mnemonic: %s\n", mnemonic); } else { printf("Error generating mnemonic.\n"); return -1; }
} getDerivedHDAddressFromMnemonic int getDerivedHDAddressFromMnemonic(const uint32_t account, const uint32_t index, const CHANGE_LEVEL change_level, const MNEMONIC mnemonic, const PASS pass, char* p2pkh_pubkey, const bool is_testnet); This function generates a new dogecoin address from a mnemonic and a slip44 key path. The function returns 0 on success and -1 on failure. C usage: #include "libdogecoin.h"
#include <stdio.h> int main () { int addressLen = P2PKHLEN; MNEMONIC seed_phrase; char address [addressLen]; dogecoin_ecc_start(); generateRandomEnglishMnemonic("256", seed_phrase); getDerivedHDAddressFromMnemonic(0, 0, "0", seed_phrase, NULL, address, false); dogecoin_ecc_stop(); printf("%s\n", seed_phrase); printf("%s\n", address);
} C++ usage: extern "C" {
#include "libdogecoin.h"
}
#include <iostream>
using namespace std; int main () { int addressLen = P2PKHLEN; MNEMONIC seed_phrase; char address [addressLen]; dogecoin_ecc_start(); generateRandomEnglishMnemonic("256", seed_phrase); getDerivedHDAddressFromMnemonic(0, 0, "0", seed_phrase, NULL, address, false); dogecoin_ecc_stop(); cout << seed_phrase << endl; cout << address << endl;
} getDerivedHDAddressFromEncryptedSeed int getDerivedHDAddressFromEncryptedSeed(const uint32_t account, const uint32_t index, const CHANGE_LEVEL change_level, char* p2pkh_pubkey, const dogecoin_bool is_testnet, const int file_num); This function generates a new Dogecoin address from an encrypted seed and a slip44 key path. The function returns 0 on success and -1 on failure. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int addressLen = P2PKHLEN; char derived_address[addressLen]; if (getDerivedHDAddressFromEncryptedSeed(0, 0, BIP44_CHANGE_EXTERNAL, derived_address, false, TEST_FILE) == 0) { printf("Derived address: %s\n", derived_address); } else { printf("Error occurred.\n"); return -1; }
} getDerivedHDAddressFromEncryptedMnemonic int getDerivedHDAddressFromEncryptedMnemonic(const uint32_t account, const uint32_t index, const CHANGE_LEVEL change_level, const PASS pass, char* p2pkh_pubkey, const bool is_testnet, const int file_num); This function generates a new Dogecoin address from an encrypted mnemonic and a slip44 key path. The function returns 0 on success and -1 on failure. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int addressLen = P2PKHLEN; char derived_address[addressLen]; if (getDerivedHDAddressFromEncryptedMnemonic(0, 0, BIP44_CHANGE_EXTERNAL, NULL, derived_address, false, TEST_FILE) == 0) { printf("Derived address: %s\n", derived_address); } else { printf("Error occurred.\n"); return -1; }
} getDerivedHDAddressFromEncryptedHDNode int getDerivedHDAddressFromEncryptedHDNode(const uint32_t account, const uint32_t index, const CHANGE_LEVEL change_level, char* p2pkh_pubkey, const bool is_testnet, const int file_num); This function generates a new Dogecoin address from an encrypted HD node and a slip44 key path. The function returns 0 on success and -1 on failure. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int addressLen = P2PKHLEN; char derived_address[addressLen]; if (getDerivedHDAddressFromEncryptedHDNode(0, 0, BIP44_CHANGE_EXTERNAL, derived_address, false, TEST_FILE) == 0) { printf("Derived address: %s\n", derived_address); } else { printf("Error occurred.\n"); return -1; }
}

