eckey: typedef struct eckey { int idx; dogecoin_key private_key; char private_key_wif[PRIVKEYWIFLEN]; dogecoin_pubkey public_key; char public_key_hex[PUBKEYHEXLEN]; char address[P2PKHLEN]; UT_hash_handle hh;
} eckey; keys: static eckey *keys = NULL; This is an empty collection of key structures and meant for internal consumption. new_eckey: eckey* new_eckey(dogecoin_bool is_testnet) { eckey* key = (struct eckey*)dogecoin_calloc(1, sizeof *key); dogecoin_privkey_init(&key->private_key); assert(dogecoin_privkey_is_valid(&key->private_key) == 0); dogecoin_privkey_gen(&key->private_key); assert(dogecoin_privkey_is_valid(&key->private_key)==1); dogecoin_pubkey_init(&key->public_key); dogecoin_pubkey_from_key(&key->private_key, &key->public_key); assert(dogecoin_pubkey_is_valid(&key->public_key) == 1); strcpy(key->public_key_hex, utils_uint8_to_hex((const uint8_t *)&key->public_key, 33)); uint8_t pkeybase58c[34]; const dogecoin_chainparams* chain = is_testnet ? &dogecoin_chainparams_test : &dogecoin_chainparams_main; pkeybase58c[0] = chain->b58prefix_secret_address; pkeybase58c[33] = 1; /* always use compressed keys */ memcpy_safe(&pkeybase58c[1], &key->private_key, DOGECOIN_ECKEY_PKEY_LENGTH); assert(dogecoin_base58_encode_check(pkeybase58c, sizeof(pkeybase58c), key->private_key_wif, sizeof(key->private_key_wif)) != 0); if (!dogecoin_pubkey_getaddr_p2pkh(&key->public_key, chain, (char*)&key->address)) return false; key->idx = HASH_COUNT(keys) + 1; return key;
} This function instantiates a new working key, but does not add it to the hash table. C usage: eckey* key = new_eckey(false); new_eckey_from_privkey: eckey* new_eckey_from_privkey(char* private_key) { eckey* key = (struct eckey*)dogecoin_calloc(1, sizeof *key); dogecoin_privkey_init(&key->private_key); const dogecoin_chainparams* chain = chain_from_b58_prefix(private_key); if (!dogecoin_privkey_decode_wif(private_key, chain, &key->private_key)) return false; assert(dogecoin_privkey_is_valid(&key->private_key)==1); dogecoin_pubkey_init(&key->public_key); dogecoin_pubkey_from_key(&key->private_key, &key->public_key); assert(dogecoin_pubkey_is_valid(&key->public_key) == 1); strcpy(key->public_key_hex, utils_uint8_to_hex((const uint8_t *)&key->public_key, 33)); uint8_t pkeybase58c[34]; pkeybase58c[0] = chain->b58prefix_secret_address; pkeybase58c[33] = 1; /* always use compressed keys */ memcpy_safe(&pkeybase58c[1], &key->private_key, DOGECOIN_ECKEY_PKEY_LENGTH); assert(dogecoin_base58_encode_check(pkeybase58c, sizeof(pkeybase58c), key->private_key_wif, sizeof(key->private_key_wif)) != 0); if (!dogecoin_pubkey_getaddr_p2pkh(&key->public_key, chain, (char*)&key->address)) return false; key->idx = HASH_COUNT(keys) + 1; return key;
} This function instantiates a new working key from a private_key in WIF format, but does not add it to the hash table. C usage: char* privkey = "QUtnMFjt3JFk1NfeMe6Dj5u4p25DHZA54FsvEFAiQxcNP4bZkPu2";
eckey* key = new_eckey_from_privkey(privkey);
... dogecoin_free(key); add_eckey: void add_eckey(eckey *key) { eckey* key_old; HASH_FIND_INT(keys, &key->idx, key_old); if (key_old == NULL) { HASH_ADD_INT(keys, idx, key); } else { HASH_REPLACE_INT(keys, idx, key, key_old); } dogecoin_free(key_old);
} This function takes a pointer to an existing working eckey object and adds it to the hash table. C usage: eckey* key = new_eckey(false);
add_eckey(key); start_key: int start_key(dogecoin_bool is_testnet) { eckey* key = new_eckey(is_testnet); int index = key->idx; add_eckey(key); return index;
} This function creates a new eckey, places it in the hash table, and returns the index of the new eckey, starting from 1 and incrementing each subsequent call. C usage: int key_id = start_key(false); find_eckey: eckey* find_eckey(int idx) { eckey* key; HASH_FIND_INT(keys, &idx, key); return key;
} This function takes an index and returns the working eckey associated with that index in the hash table. C usage: ...
int key_id = start_key(false);
eckey* key = find_eckey(key_id);
