These functions implement the core functionality of Libdogecoin for building transactions, and are described in depth below. You can access them through a C program, by including the libdogecoin.h header in the source code and including the libdogecoin.a library at compile time. start_transaction int start_transaction() This function instantiates a new working_transaction structure and returns its index for future retrieval as an integer. This new working_transaction will contain an empty hex, which is "01000000000000000000". Note that anytime a new working transaction is created, it must also be removed at the end of the session by calling either clear_transaction(), otherwise a memory leak may occur. C usage: #include "libdogecoin.h" int main() { int index = start_transaction(); // build onto the working transaction here clear_transaction(index);
} add_utxo int add_utxo(int txindex, char* hex_utxo_txid, int vout) An unspent transaction output (utxo) is an output of a previous transaction in which funds were sent to the user's address. These can be spent by including them as inputs in a new transaction. This function takes in a working_transaction's index as an integer (txindex), a raw hexadecimal string id of the transaction containing the utxo to spend (hex_utxo_txid), and index of the desired utxo within the previous transaction's list of outputs (vout). The utxo is then added to the working_transaction->transaction->vin field, returning either 1 for success or 0 for failure. C usage: #include "libdogecoin.h" int main() { char* prev_output_txid = "b4455e7b7b7acb51fb6feba7a2702c42a5100f61f61abafa31851ed6ae076074"; // worth 2 dogecoin int prev_output_n = 1; int index = start_transaction(); if (!add_utxo(index, prev_output_txid, prev_output_n)) { // handle failure, return false; or printf("failure\n"); etc... } clear_transaction(index);
} add_output int add_output(int txindex, char* destinationaddress, char* amount) In order to actually spend utxos, the user must specify the new recipient address and how much of the total input amount will be sent to this address. This function takes in a working_transaction's index as an integer (txindex), the string p2pkh address of the new recipient (destinationaddress), and the amount in Dogecoin (amount) to send. This new output will be added to the working_transaction->transaction->vout field, returning either 1 for success or 0 for failure. C usage: #include "libdogecoin.h" int main() { char* prev_output_txid = "42113bdc65fc2943cf0359ea1a24ced0b6b0b5290db4c63a3329c6601c4616e2"; // worth 10 dogecoin int prev_output_n = 1; char* external_address = "nbGfXLskPh7eM1iG5zz5EfDkkNTo9TRmde"; int index = start_transaction(); add_utxo(index, prev_output_txid, prev_output_n); if (!add_output(index, external_address, "5.0")) { // 5 dogecoin to be sent // error handling here } clear_transaction(index);
} finalize_transaction char* finalize_transaction(int txindex, char* destinationaddress, char* subtractedfee, char* out_dogeamount_for_verification, char* changeaddress) Because Dogecoin protocol requires that utxos must be spent in full, an additional output is usually included in a transaction to return all the leftover funds to the sender. This function automatically handles both creating this extra output and reserving some funds for the network fee. It takes in a working_transaction's index as an integer (txindex), the external destination address we are sending to (destinationaddress), the desired fee to be subtracted (subtractedfee), the total amount of all inputs included through add_utxo() (out_dogeamount_for_verification), and the public key of the sender (public_key). In addition to making change and deducting the fee, it checks that all of the recipients included in the transaction outputs are valid by converting their script hashes to p2pkh, and returns false if any are not found. Otherwise, the hex of the finalized transaction is returned as a string. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { char* prev_output_txid_2 = "b4455e7b7b7acb51fb6feba7a2702c42a5100f61f61abafa31851ed6ae076074"; // worth 2 dogecoin char* prev_output_txid_10 = "42113bdc65fc2943cf0359ea1a24ced0b6b0b5290db4c63a3329c6601c4616e2"; // worth 10 dogecoin int prev_output_n_2 = 1; int prev_output_n_10 = 1; char* external_address = "nbGfXLskPh7eM1iG5zz5EfDkkNTo9TRmde"; char* my_address = "noxKJyGPugPRN4wqvrwsrtYXuQCk7yQEsy"; int index = start_transaction(); add_utxo(index, prev_output_txid_2, prev_output_n_2); add_utxo(index, prev_output_txid_10, prev_output_n_10); add_output(index, external_address, "5.0"); // finalize transaction with min fee of 0.00226 doge on the input total of 12 dogecoin char* rawhex = finalize_transaction(index, external_address, "0.00226", "12.0", my_address); printf("Finalized transaction hex is %s.", rawhex); clear_transaction(index);
} get_raw_transaction char* get_raw_transaction(int txindex) This function takes in a working_transaction's index as an integer (txindex) and returns the current working_transaction in raw hexadecimal format. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int index = start_transaction(); char* rawhex = get_raw_transaction(index); printf("The transaction hex at index %d is %s.\n", index, rawhex); clear_transaction(index);
} clear_transaction void clear_transaction(int txindex) This function takes in a working_transaction's index as an integer (txindex), and removes the transaction at that index from the hash table. All memory dedicated to transaction objects, such as dogecoin_tx_in and dogecoin_tx_out, is freed from within this function. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { int index = start_transaction(); clear_transaction(index); printf("The transaction hex at index %d is %s.\n", index, get_raw_transaction(index)); // should return (null)
} sign_raw_transaction int sign_raw_transaction(int inputindex, char* incomingrawtx, char* scripthex, int sighashtype, char* privkey) This function takes in an index denoting which of the current transaction's inputs to sign (inputindex), the raw hexadecimal representation of the transaction to sign (incomingrawtx), the pubkey script in hexadecimal format (scripthex), the signature hash type (sighashtype) and the WIF-encoded private key used to sign the input (privkey). Signature hash type in normal use cases is set to 1 to denote that anyone can pay. In C, the function returns a boolean denoting success, but the actual signed transaction hex is passed back through incomingrawtx. Important: sign_raw_transaction must be run within a secp256k1 context, which can be created by calling dogecoin_ecc_start() and dogecoin_ecc_stop() as shown below. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { char* prev_output_txid_2 = "b4455e7b7b7acb51fb6feba7a2702c42a5100f61f61abafa31851ed6ae076074"; // worth 2 dogecoin char* prev_output_txid_10 = "42113bdc65fc2943cf0359ea1a24ced0b6b0b5290db4c63a3329c6601c4616e2"; // worth 10 dogecoin int prev_output_n_2 = 1; int prev_output_n_10 = 1; char* external_address = "nbGfXLskPh7eM1iG5zz5EfDkkNTo9TRmde"; char* my_address = "noxKJyGPugPRN4wqvrwsrtYXuQCk7yQEsy"; char* my_script_pubkey = "76a914d8c43e6f68ca4ea1e9b93da2d1e3a95118fa4a7c88ac"; char* my_privkey = "ci5prbqz7jXyFPVWKkHhPq4a9N8Dag3TpeRfuqqC2Nfr7gSqx1fy"; int index = start_transaction(); add_utxo(index, prev_output_txid_2, prev_output_n_2); add_utxo(index, prev_output_txid_10, prev_output_n_10); add_output(index, external_address, "5.0"); finalize_transaction(index, external_address, "0.00226", "12.0", my_address); //sign both inputs of the current finalized transaction dogecoin_ecc_start(); char* rawhex = get_raw_transaction(index); sign_raw_transaction(0, rawhex, my_script_pubkey, 1, my_privkey); sign_raw_transaction(1, rawhex, my_script_pubkey, 1, my_privkey); dogecoin_ecc_stop(); printf("The final signed transaction hex is: %s\n", rawhex); clear_transaction(index);
} sign_transaction int sign_transaction(int txindex, char* script_pubkey, char* privkey) This function takes in a working transaction structure's index as an integer (txindex), the pubkey in script hex form (script_pubkey) and the WIF-encoded private key (privkey). Each input is then signed using the specified private key, and the final signed transaction is saved to the hash table, which can be retrieved using get_raw_transaction(). The return value of sign_transaction() is a boolean denoting whether the signing was successful, but the output from get_raw_transaction() is a fully signed transaction that--if all information is valid--can be broadcast to miners and incorporated into the blockchain. Important: sign_transaction must also be run within a secp256k1 context, which can be created by calling dogecoin_ecc_start() and dogecoin_ecc_stop() as shown below. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { char* prev_output_txid_2 = "b4455e7b7b7acb51fb6feba7a2702c42a5100f61f61abafa31851ed6ae076074"; // worth 2 dogecoin char* prev_output_txid_10 = "42113bdc65fc2943cf0359ea1a24ced0b6b0b5290db4c63a3329c6601c4616e2"; // worth 10 dogecoin int prev_output_n_2 = 1; int prev_output_n_10 = 1; char* external_address = "nbGfXLskPh7eM1iG5zz5EfDkkNTo9TRmde"; char* my_address = "noxKJyGPugPRN4wqvrwsrtYXuQCk7yQEsy"; char* my_script_pubkey = "76a914d8c43e6f68ca4ea1e9b93da2d1e3a95118fa4a7c88ac"; char* my_privkey = "ci5prbqz7jXyFPVWKkHhPq4a9N8Dag3TpeRfuqqC2Nfr7gSqx1fy"; int index = start_transaction(); add_utxo(index, prev_output_txid_2, prev_output_n_2); add_utxo(index, prev_output_txid_10, prev_output_n_10); add_output(index, external_address, "5.0"); finalize_transaction(index, external_address, "0.00226", "12.0", my_address); //sign both inputs of the current finalized transaction dogecoin_ecc_start(); if (!sign_transaction(index, my_script_pubkey, my_privkey)) { // error handling here } dogecoin_ecc_stop(); printf("The final signed transaction hex is: %s\n", get_raw_transaction(index)); clear_transaction(index);
} store_raw_transaction int store_raw_transaction(char* incomingrawtx) This function is equivalent to save_raw_transaction but takes the next available index in the hash table to save the provided transaction hex (incomingrawtx), rather than allowing the user to specify which index. It then returns this automatically chosen index as an integer. C usage: #include "libdogecoin.h"
#include <stdio.h> int main() { char* hex_to_store = "0100000001746007aed61e8531faba1af6610f10a5422c70a2a7eb6ffb51cb7a7b7b5e45b40100000000ffffffff0000000000"; int index = store_raw_transaction(hex_to_store); printf("The transaction hex at index %d is %s.\n", index, get_raw_transaction(index)); clear_transaction(index);
}

